<template>
  <div class="header-2-body">
    <span>{{ projectName }}</span>
    <p class="time">{{ formattedDateTime.date }}&nbsp;<br/> {{ formattedDateTime.time }}&nbsp;&nbsp;</p>

    <!-- 左侧菜单 -->
    <ul class="header-card-box">
      <li
          v-for="(item, index) in headerCardData"
          :key="index"
          :class="item.isSelect ? 'on' : ''"
          @click="handleMenuClick(item, index, 1)"
      >
        <div class="menu-name">
          <div class="icon"></div>
          <span>{{ item.name }}</span>
        </div>
        <div
            class="headerCardMenu-box"
            v-if="item.childMenuArray"
            :class="getMenuClass(item.childMenuArray.length)"
        >
          <span
              v-for="(subItem, subIndex) in item.childMenuArray"
              :key="subIndex"
              @click.stop="jumpPath(subItem, item)"
          >
            {{ subItem.name }}
          </span>
        </div>
      </li>
    </ul>

    <!-- 右侧菜单 -->
    <ul class="header-card-boxright">
      <li
          v-for="(item, index) in headerCardData2"
          :key="index"
          :class="item.isSelect ? 'on' : ''"
          @click="handleMenuClick(item, index, 2)"
      >
        <div class="menu-name">
          <div class="icon"></div>
          <span>{{ item.name }}</span>
        </div>
        <div
            class="headerCardMenu-box"
            v-if="item.childMenuArray"
            :class="getMenuClass(item.childMenuArray.length)"
        >
          <span
              v-for="(subItem, subIndex) in item.childMenuArray"
              :key="subIndex"
              @click.stop="jumpPath(subItem, item)"
          >
            {{ subItem.name }}
          </span>
        </div>
      </li>
    </ul>

    <!-- 用户信息 -->
    <el-dropdown @command="handleCommand">
      <div class="header-user-info">
        <img src="../../assets/image/header/user-icon.png" alt="user icon">
        <ul>
          <li>{{ userInfo.username || '未知用户' }}</li>
          <li>{{ userInfo.roleList && userInfo.roleList[0] ? userInfo.roleList[0].roleName : '未分配角色' }}</li>
        </ul>
      </div>
      <el-dropdown-menu slot="dropdown">
        <el-dropdown-item divided command="accreditInfo">
          <i class="icon zhb-iconfont zhb-iconshenhe"></i>
          授权信息
        </el-dropdown-item>
        <el-dropdown-item divided command="updatePassword">
          <i class="icon zhb-iconfont zhb-iconzhongzhimima"></i>
          修改密码
        </el-dropdown-item>
        <el-dropdown-item divided command="logout">
          <i class="icon zhb-iconfont zhb-icontuichudenglu"></i>
          退出登录
        </el-dropdown-item>
      </el-dropdown-menu>
    </el-dropdown>
    <!--修改密码===============-->
    <LTDialog
        v-if="editPasswordMsg.isShow"
        :DialogLTMsg="editPasswordMsg"
        @close="editPasswordMsg.isShow = false"
    >
      <editPassword @cancel="editPasswordMsg.isShow = false"></editPassword>
    </LTDialog>
    <!--授权信息===============-->
    <LTDialog
        v-if="licenseMsg.isShow"
        :DialogLTMsg="licenseMsg"
        @close="licenseMsg.isShow = false"
    >
      <license @cancel="licenseMsg.isShow = false"></license>
    </LTDialog>

    <!--END!===============-->

  </div>
</template>

<script>
import { LogOutApi} from "@/api/System/user.js";
import { resetAuthErrorCount } from "@/utils/request.js";
import editPassword from "./components/editPassword.vue";
import license from "./components/license.vue";

export default {
  name: "Header",
  components: {license, editPassword},
  props: {
    title: {
      type: String,
      default: "视频监管平台"
    }
  },

  data() {
    return {
      projectName: this.title,
      date: "",
      time: "",
      week: ['周日', '周一', '周二', '周三', '周四', '周五', '周六'],
      userInfo: {},
      userForm: {},
      headerCardData2: [],
      headerCardData: [],
      timer: null, // 定时器引用，用于清理
      editPasswordMsg: {
        isShow: false,
        title: '修改密码',
        //showCloseBtn: true,
        styles: {
          width: '30%',
          height: '45%'
        }
      },
      licenseMsg: {
        title: '授权信息',
        isShow: false,
        styles: {
          width: "40%",
          height: "50%",
        },
      },
    };
  },

  computed: {
    formattedDateTime() {
      const now = new Date();
      return {
        time: now.toTimeString().slice(0, 8),
        date: now.toLocaleDateString('zh-CN', {
          year: 'numeric',
          month: '2-digit',
          day: '2-digit'
        })
      };
    }
  },

  created() {
    this.initProjectName();
    this.updateTime();
    this.timer = setInterval(this.updateTime, 1000);
    this.initMenuData();
  },

  mounted() {
    this.initUserInfo();
  },

  beforeDestroy() {
    if (this.timer) {
      clearInterval(this.timer);
    }
  },

  methods: {
    // 初始化项目名称
    initProjectName() {
      this.projectName = '前端Vue2.x UI组件库'
    },

    // 初始化菜单数据
    initMenuData() {
      try {
        const menuData = JSON.parse(localStorage.getItem("DocsMenuData")) || [];
        // 使用 slice() 进行浅拷贝，避免修改原始数据
        this.headerCardData = menuData.slice(0, 4);
        this.headerCardData2 = menuData.slice(4);
      } catch (error) {
        console.error('Failed to parse menu data:', error);
        this.headerCardData = [];
        this.headerCardData2 = [];
      }
    },

    // 初始化用户信息
    initUserInfo() {
      try {
        const userInfoStr = localStorage.getItem("userInfo");
        this.userInfo = userInfoStr ? JSON.parse(userInfoStr) : {};
      } catch (error) {
        console.error('Failed to parse user info:', error);
        this.userInfo = {};
      }
    },

    // 更新时间
    updateTime() {
      const now = new Date();
      this.time = now.toTimeString().slice(0, 8);
      this.date = now.toLocaleDateString('zh-CN', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit'
      });
    },

    // 获取菜单类名
    getMenuClass(length) {
      const classMap = {
        3: 'headerCardMenuThree',
        4: 'headerCardMenuFour',
        5: 'headerCardMenuFive'
      };
      return classMap[length] || '';
    },

    // 处理菜单点击
    handleMenuClick(item, index, menuType) {
      if (!item.url) return;

      this.clearMenuSelection();
      this.updateMenuSelection(item, index, menuType);
      this.$router.push(item.url);
    },

    // 更新菜单选择状态
    updateMenuSelection(item, index, menuType) {
      const menuArray = menuType === 1 ? this.headerCardData : this.headerCardData2;
      const menuItem = menuArray[index];

      menuItem.isSelect = true;
      if (item.children && item.children.length > 0) {
        menuItem.isChildrenSelect = true;
      }

      // 更新本地存储
      localStorage.setItem("menuData", JSON.stringify([
        ...this.headerCardData,
        ...this.headerCardData2
      ]));
    },

    // 清除所有菜单选择状态
    clearMenuSelection() {
      [...this.headerCardData, ...this.headerCardData2].forEach(item => {
        item.isSelect = false;
        item.isChildrenSelect = false;
      });
    },

    // 跳转到子菜单
    jumpPath(subItem, item) {
      this.clearMenuSelection();
      item.isSelect = true;
      this.$router.push(subItem.url);

      // 更新本地存储
      localStorage.setItem("menuData", JSON.stringify([
        ...this.headerCardData,
        ...this.headerCardData2
      ]));
    },

    // 处理命令（用户菜单选项）
    async handleCommand(command) {
      try {
        if (command === 'logout') {
          await this.handleLogout();
        } else if (command === 'updatePassword') {
          this.editPasswordMsg.isShow = true;
        } else if (command === 'accreditInfo') {
          this.licenseMsg.isShow = true;
        }
      } catch (error) {
        console.error('Command execution error:', error);
        this.$message.error("操作失败，请重试");
      }
    },

    // 处理登出
    async handleLogout() {
      const res = await LogOutApi();
      if (res.data.code === 2000) {
        resetAuthErrorCount();
        this.$message.success({
          message: "注销成功！",
          showClose: true,
          duration: 1000
        });
        this.$nextTick(() => {
          this.$router.push('/');
        });
      } else {
        this.$message.error({
          message: res.data.message || "注销失败",
          showClose: true,
          duration: 1000
        });
      }
    },


  }
};
</script>

